// middleware.ts
import { getToken } from "next-auth/jwt";
import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";

export async function middleware(req: NextRequest) {
  const { pathname } = req.nextUrl;
  const baseUrl = process.env.NEXTAUTH_URL!;

  // let next-auth and static files through
  if (
    pathname.startsWith("/api/auth") ||
    pathname.startsWith("/_next") ||
    pathname.includes(".") ||
    pathname.startsWith("/auth/signin")
  ) {
    return NextResponse.next();
  }

  // check for a valid NextAuth JWT
  const token = await getToken({
    req,
    secret: process.env.NEXTAUTH_SECRET,
  });

  if (!token) {
    // Use NextAuth's signin but trigger automatic redirect
    const signInUrl = new URL(`${baseUrl}/api/auth/signin`);

    // Preserve original URL with all query parameters (including UTM params)
    const originalUrl = new URL(req.url);
    const callbackUrl = `${baseUrl}${pathname}${originalUrl.search}`;

    signInUrl.searchParams.set("callbackUrl", callbackUrl);
    return NextResponse.redirect(signInUrl);
  }

  return NextResponse.next();
}

